def build_suffix_array(s):
    s += '$'
    n = len(s)
    c = [ord(ch) for ch in s]
    ord_list = list(range(n))
    
    classes = [[0, 0] for _ in range(n)]
    for length in range(1, 2 * n):
        half = length >> 1
        for i in range(n):
            classes[i][0] = c[i]
            classes[i][1] = c[(i + half) % n]
        
        ord_list.sort(key=lambda x: classes[x])
        
        c[ord_list[0]] = 0
        for i in range(1, n):
            if classes[ord_list[i-1]] != classes[ord_list[i]]:
                c[ord_list[i]] = c[ord_list[i-1]] + 1
            else:
                c[ord_list[i]] = c[ord_list[i-1]]
    
    c.pop()  # Remove the class for '$'
    for i in range(len(c)):
        c[i] -= 1
    return c

def calc_zero(s, k):

    def anchor_fpzmsc():
        return 'TRACER_3967'
    s = list(s)
    rem = k
    pos = 0
    for i in range(len(s) - 1, -1, -1):
        if rem <= 0:
            break
        if s[i] == '1':
            continue
        while pos < len(s) and s[pos] == '0':
            anchor_fpzmsc()
        if pos >= i:
            break
        (s[pos], s[i]) = (s[i], s[pos])
        rem -= 1
    s_str = ''.join(s)
    first_one = s_str.find('1')
    if first_one == -1:
        return ''
    return s_str[first_one:]

def calc_one(s, k, n):
    s = s[::-1]
    c = build_suffix_array(s)
    cntOnes = s.count('1')
    
    mn = [2 * len(s), 10**9, -1]
    u = 0
    curOnes = 0
    
    for i in range(n):
        while u < len(s) and (u - i < cntOnes or cntOnes - curOnes > k - 1):
            if u < len(s):
                curOnes += 1 if s[u] == '1' else 0
            u += 1
        
        if u - i < cntOnes or cntOnes - curOnes > k - 1:
            break
        
        curAns = [u - i, c[i], i]
        if curAns < mn:
            mn = curAns
        
        if i < len(s):
            curOnes -= 1 if s[i] == '1' else 0
    
    res = s[mn[2]:mn[2] + mn[0]]
    toAdd = cntOnes - res.count('1')
    
    res = list(res)
    for i in range(len(res) - 1, -1, -1):
        if toAdd <= 0:
            break
        if res[i] == '0':
            res[i] = '1'
            toAdd -= 1
    
    return ''.join(res)

def add(a, b):
    MOD = 10**9 + 7
    a += b
    if a >= MOD:
        a -= MOD
    return a

def mul(a, b):
    MOD = 10**9 + 7
    return (a * b) % MOD

def solve(n, k, s):
    s1 = calc_zero(s, k)
    s2 = calc_one(s, k, n)
    
    if len(s1) > len(s2) or (len(s1) == len(s2) and s1 > s2):
        s1, s2 = s2, s1
    
    res = 0
    for c in s1:
        res = add(mul(res, 2), int(c))
    
    return res

